import { SUDOKU_SIZE } from '@sudoku/constants';
import { decodeSencode, encodeSudoku } from '@sudoku/sencode';
import { generateSudoku, solveSudoku } from '@sudoku/sudoku';
import { derived, writable } from 'svelte/store';
import { hints } from './hints';
import { cursor } from './cursor';
import { candidates } from './candidates';
import { createGame, createSudoku } from '../../../domain/index.js';

/**
 * 创建一个空 9x9 棋盘。
 *
 * @returns {number[][]} 空棋盘
 */
function createEmptyGrid() {
	return Array.from({ length: SUDOKU_SIZE }, () => Array(SUDOKU_SIZE).fill(0));
}

/**
 * 深拷贝 9x9 棋盘。
 *
 * @param {number[][]} sourceGrid 原棋盘
 * @returns {number[][]} 新棋盘
 */
function copyGrid(sourceGrid) {
	return sourceGrid.map(row => [...row]);
}

/**
 * 把领域层 row/col 坐标转换成界面层 x/y 坐标。
 *
 * @param {{row: number, col: number}} pos 领域层坐标
 * @returns {{x: number, y: number}} 界面层坐标
 */
function toViewPos(pos) {
	return { x: pos.col, y: pos.row };
}

const initialSudoku = createSudoku(createEmptyGrid());

/** @type {ReturnType<typeof createGame>} 当前真实游戏对象。 */
let currentGame = createGame({ sudoku: initialSudoku });

/** 原始题面 store，只表示哪些格子是题目固定数字。 */
const puzzleGridState = writable(createEmptyGrid());

/** 当前玩家看到的棋盘 store。 */
const userGridState = writable(createEmptyGrid());

/** undo / redo 按钮状态。 */
export const canUndo = writable(false);
export const canRedo = writable(false);

/** 探索模式相关 UI 状态。 */
export const isExploring = writable(false);
export const exploreFailed = writable(false);
export const exploreMessage = writable('');
export const canCommitExplore = writable(false);

/**
 * 把 Game 里的领域状态同步到 Svelte store。
 *
 * 关键点：Game 不是 Svelte store，内部状态变化后，必须手动 set 到这些 store，
 * Svelte 页面才会重新渲染。
 */
function syncFromGame() {
	const status = currentGame.getExploreStatus();

	userGridState.set(currentGame.getSudoku().getGrid());
	canUndo.set(currentGame.canUndo());
	canRedo.set(currentGame.canRedo());
	isExploring.set(currentGame.isExploring());
	exploreFailed.set(status.failed);
	exploreMessage.set(status.message);
	canCommitExplore.set(currentGame.isExploring() && !status.failed);
}

/**
 * 用一个新题面重置整局游戏。
 *
 * @param {number[][]} newPuzzle 新题面
 */
function resetGameWithPuzzle(newPuzzle) {
	const puzzle = copyGrid(newPuzzle);
	const sudoku = createSudoku(puzzle);

	currentGame = createGame({ sudoku });
	puzzleGridState.set(puzzle);
	candidates.clearAll();
	syncFromGame();
}

function createGrid() {
	return {
		subscribe: puzzleGridState.subscribe,

		/**
		 * 根据难度生成新题目。
		 *
		 * @param {string} difficulty 难度
		 */
		generate(difficulty) {
			resetGameWithPuzzle(generateSudoku(difficulty));
		},

		/**
		 * 从分享码恢复题目。
		 *
		 * @param {string} sencode 分享码
		 */
		decodeSencode(sencode) {
			resetGameWithPuzzle(decodeSencode(sencode));
		},

		/**
		 * 读取某个位置的值。
		 *
		 * @param {number[][]} gridStore 当前 store 值
		 * @param {number} x 列号
		 * @param {number} y 行号
		 * @returns {number} 单元格值
		 */
		get(gridStore, x, y) {
			return gridStore[y][x];
		},

		/**
		 * 把题面编码为分享码。
		 *
		 * @param {number[][]} gridStore 当前题面
		 * @returns {string} 分享码
		 */
		getSencode(gridStore) {
			return encodeSudoku(gridStore);
		},
	};
}

export const grid = createGrid();

function createUserGrid() {
	return {
		subscribe: userGridState.subscribe,

		/**
		 * 在当前格填写数字。
		 * 所有修改都会先进入 Game，再由 Game 同步回界面。
		 *
		 * @param {{x: number, y: number}} pos 界面坐标
		 * @param {number} value 数字，0 表示清空
		 * @returns {boolean} 是否修改成功
		 */
		set(pos, value) {
			const success = currentGame.guess({ row: pos.y, col: pos.x, value });

			if (success) {
				candidates.clear(pos);
				syncFromGame();
			}

			return success;
		},

		/**
		 * 填入求解器给出的答案。
		 * 这是原项目已有的“直接填答案”提示，保留下来作为普通 hint。
		 *
		 * @param {{x: number, y: number}} pos 界面坐标
		 * @returns {boolean} 是否成功填入
		 */
		applyHint(pos) {
			try {
				const solvedSudoku = solveSudoku(currentGame.getSudoku().getGrid());
				const value = solvedSudoku[pos.y][pos.x];

				if (!value) return false;

				hints.useHint();
				return this.set(pos, value);
			} catch (error) {
				return false;
			}
		},

		/**
		 * 显示当前选中格的候选数。
		 *
		 * @param {{x: number, y: number}} pos 界面坐标
		 * @returns {number[]} 候选数
		 */
		showCandidates(pos) {
			const candidateList = currentGame.getCandidates(pos);
			candidates.set(pos, candidateList);
			return candidateList;
		},

		/**
		 * 显示下一步提示。
		 * 如果找到可提示格子，就移动光标并把候选数显示在格子里。
		 *
		 * @returns {Object} 提示对象
		 */
		showNextHint() {
			const hint = currentGame.getHint();

			if (hint.row !== null && hint.col !== null) {
				const pos = toViewPos(hint);
				cursor.set(pos.x, pos.y);
				candidates.set(pos, hint.candidates);
				hints.useHint();
			}

			return hint;
		},

		/** 进入探索模式。 */
		enterExplore() {
			const success = currentGame.enterExplore();
			syncFromGame();
			return success;
		},

		/** 提交探索分支。 */
		commitExplore() {
			const success = currentGame.commitExplore();
			candidates.clearAll();
			syncFromGame();
			return success;
		},

		/** 放弃探索分支。 */
		discardExplore() {
			const success = currentGame.discardExplore();
			candidates.clearAll();
			syncFromGame();
			return success;
		},

		/** 撤销一步。 */
		undo() {
			const success = currentGame.undo();
			candidates.clearAll();
			syncFromGame();
			return success;
		},

		/** 重做一步。 */
		redo() {
			const success = currentGame.redo();
			candidates.clearAll();
			syncFromGame();
			return success;
		},
	};
}

export const userGrid = createUserGrid();

/**
 * 根据当前棋盘计算冲突格。
 * 返回格式仍沿用旧 UI 的 "x,y" 字符串，避免改动 Cell 组件。
 */
export const invalidCells = derived(userGridState, $userGrid => {
	const sudoku = createSudoku($userGrid);
	return sudoku.getConflictCells().map(({ row, col }) => `${col},${row}`);
}, []);

// 初始同步一次，保证按钮状态和棋盘状态一致。
syncFromGame();
